        if term.len() < 2 {
            continue;
        }
        let in_name = !name.is_empty() && name.contains(term);
        let in_path = path.contains(term);
        let in_ctx = !ctx.is_empty() && ctx.contains(term);
        let in_content = content.contains(term);

        if in_name {
            raw += 0.7;
            matched_terms += 1;
            strong_hit = true;
        } else if in_path {
            raw += 0.55;
            matched_terms += 1;
            strong_hit = true;
        } else if in_ctx {
            raw += 0.45;
            matched_terms += 1;
        } else if in_content {
            raw += 0.2;
            matched_terms += 1;
        }
    }

