pub async fn search_code(
    state: &Arc<AppState>,
    params: SearchCodeParams,
) -> anyhow::Result<CallToolResult> {
    crate::ensure_embedding_ready!(state);

    let SearchCodeParams {
        query,
        project_id,
        limit,
    } = params;
    let project_id = normalize_project_id(project_id);

    let mut is_partial = false;
    let mut indexing_message = None;

    let mut project_status = None;
    if let Some(ref project_id) = project_id {
        if let Ok(Some(status)) = state.storage.get_index_status(project_id).await {
            if status.status == crate::types::IndexState::Indexing
                || status.status == crate::types::IndexState::EmbeddingPending
            {
                is_partial = true;
                indexing_message = Some(format!(
                    "Indexing in progress ({}/{} files). Results may be incomplete.",
                    status.indexed_files, status.total_files
                ));
            }
            project_status = Some(status);
        }
    }

    let query_embedding = state.embedding.embed(&query).await?;

    let limit = normalize_limit(limit);

    // Run vector search and BM25 in parallel for robust results.
    // Previously BM25 was only a fallback — degenerate vectors masked BM25 entirely.
    let project_id = project_id.as_deref();
    let (vector_results, bm25_results) = tokio::join!(
        async {
            match state
                .storage
                .vector_search_code(&query_embedding, project_id, limit)
                .await
            {
                Ok(results) => {
                    tracing::debug!(hits = results.len(), "search_code: vector search completed");
                    results
                }
                Err(e) => {
                    tracing::warn!(error = %e, "search_code: vector search failed, falling back to empty");
                    Vec::new()
                }
            }
        },
        async {
            state
                .code_search
                .search(&query, project_id, limit, state.storage.as_ref())
                .await
        }
    );

    // Merge: vector results first, then BM25 results not already present.
    // This gives vector priority in ranking while ensuring BM25 fills gaps.
    use std::collections::HashSet;
    let mut seen_ids: HashSet<String> = HashSet::new();
    let mut merged = Vec::with_capacity(limit);

    for r in &vector_results {
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "vector"
            }));
        }
        if merged.len() >= limit {
            break;
        }
    }

    for r in &bm25_results {
        if merged.len() >= limit {
            break;
        }
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "bm25"
            }));
        }
    }

    Ok(success_json(json!({
        "results": merged,
        "count": merged.len(),
        "summary": summary_collection_response(
            "collection",
            merged.len(),
            Some(merged.len()),
            is_partial,
            indexing_message.clone(),
        ),
        "query": query,
        "contract": code_search_contract_json(project_id, project_status.as_ref()),
        "vector_hits": vector_results.len(),
        "bm25_hits": bm25_results.len(),
        "is_partial": is_partial,
        "message": indexing_message
    })))
}

                data: None,
            })?;
            let relation_type = params.0.relation_type.ok_or_else(|| ErrorData {
                code: ErrorCode(-32602),
                message: "relation_type required for create_relation".into(),
                data: None,
            })?;
            let relation_params = CreateRelationParams {
                from_entity,
                to_entity,
                relation_type,
                weight: params.0.weight,
            };
            logic::graph::create_relation(&self.state, relation_params)
                .await
                .map_err(to_rpc_error)
        }
        "get_related" => {
            let entity_id = params.0.entity_id.ok_or_else(|| ErrorData {
                code: ErrorCode(-32602),
                message: "entity_id required for get_related".into(),
                data: None,
            })?;
            let related_params = GetRelatedParams {
                entity_id,
                depth: params.0.depth,
                direction: params.0.direction,
            };
            logic::graph::get_related(&self.state, related_params)
                .await
                .map_err(to_rpc_error)
        }
        "detect_communities" => {
            let community_params = DetectCommunitiesParams { _placeholder: false };
            logic::graph::detect_communities(&self.state, community_params)
                .await
                .map_err(to_rpc_error)
        }
        other => Err(ErrorData {
            code: ErrorCode(-32602),
            message: format!("Invalid action '{}'. Use: create_entity, create_relation, get_related, detect_communities", other).into(),
            data: None,
        }),
    }
}

#[tool(
    description = "Get valid memories. Supports optional timestamp (ISO 8601), scope filters, memory_type, metadata_filter, and event/ingestion ranges. Response includes additive contract and summary metadata."
)]
async fn get_valid(
    &self,
    params: Parameters<GetValidParams>,
) -> Result<CallToolResult, ErrorData> {
    if let Some(ref ts) = params.0.timestamp {
        let at_params = GetValidAtParams {
            timestamp: ts.clone(),
            user_id: params.0.user_id.clone(),
            agent_id: params.0.agent_id.clone(),
            run_id: params.0.run_id.clone(),
            namespace: params.0.namespace.clone(),
            memory_type: params.0.memory_type.clone(),
            metadata_filter: params.0.metadata_filter.clone(),
            event_after: params.0.event_after.clone(),
            event_before: params.0.event_before.clone(),
            ingestion_after: params.0.ingestion_after.clone(),
            ingestion_before: params.0.ingestion_before.clone(),
            limit: params.0.limit,
        };
        logic::memory::get_valid_at(&self.state, at_params)
            .await
            .map_err(to_rpc_error)
    } else {
        logic::memory::get_valid(&self.state, params.0)
            .await
            .map_err(to_rpc_error)
    }
}

#[tool(description = "Soft-delete memory, optionally linking replacement.")]
async fn invalidate(
